  1→import {
  2→  type ReactNode,
  3→  useCallback,
  4→  useEffect,
  5→  useMemo,
  6→  useRef,
  7→  useState,
  8→} from 'react';
  9→import './list.scss';
 10→import { ListContext } from './list_context';
 11→
 12→interface ListProps {
 13→  children: ReactNode;
 14→  itemCount: number;
 15→  onActiveIndexChange?: (index: number) => void;
 16→  onAction?: (index: number) => void;
 17→}
 18→
 19→export function List({
 20→  children,
 21→  itemCount,
 22→  onActiveIndexChange,
 23→  onAction,
 24→}: ListProps) {
 25→  const [activeIndex, setActiveIndexRaw] = useState(0);
 26→  const containerRef = useRef<HTMLDivElement>(null);
 27→
 28→  const setActiveIndex = useCallback(
 29→    (index: number) => {
 30→      setActiveIndexRaw(index);
 31→      onActiveIndexChange?.(index);
 32→    },
 33→    [onActiveIndexChange],
 34→  );
 35→
 36→  useEffect(() => {
 37→    if (itemCount === 0) {
 38→      setActiveIndex(0);
 39→    } else if (activeIndex >= itemCount) {
 40→      setActiveIndex(itemCount - 1);
 41→    }
 42→  }, [
 43→    itemCount,
 44→    activeIndex,
 45→    setActiveIndex,
 46→  ]);
 47→
 48→  useEffect(() => {
 49→    const container = containerRef.current;
 50→    if (!container) return;
 51→
 52→    const activeElement = container.querySelector<HTMLElement>(
 53→      `[data-list-index="${activeIndex}"]`,
 54→    );
 55→    activeElement?.scrollIntoView({ block: 'nearest' });
 56→  }, [activeIndex]);
 57→
 58→  useEffect(() => {
 59→    function handleKeyDown(e: KeyboardEvent) {
 60→      if (itemCount === 0) return;
 61→      if (
 62→      e.metaKey ||
 63→      e.ctrlKey ||
 64→      e.altKey ||
 65→      e.shiftKey
 66→      ) {
 67→        return;
 68→      }
 69→
 70→      if (e.key === 'ArrowDown') {
 71→        e.preventDefault();
 72→        setActiveIndex(activeIndex < itemCount - 1 ? activeIndex + 1 : 0);
 73→      } else if (e.key === 'ArrowUp') {
 74→        e.preventDefault();
 75→        setActiveIndex(activeIndex > 0 ? activeIndex - 1 : itemCount - 1);
 76→      } else if (e.key === 'Enter') {
 77→        e.preventDefault();
 78→        onAction?.(activeIndex);
 79→      }
 80→    }
 81→
 82→    window.addEventListener('keydown', handleKeyDown);
 83→    return () => window.removeEventListener('keydown', handleKeyDown);
 84→  }, [
 85→    activeIndex,
 86→    itemCount,
 87→    setActiveIndex,
 88→    onAction,
 89→  ]);
 90→
 91→  const contextValue = useMemo(
 92→    () => ({
 93→      activeIndex,
 94→      setActiveIndex,
 95→    }),
 96→    [
 97→      activeIndex,
 98→      setActiveIndex,
 99→    ],
100→  );
101→
102→  return (
103→    <ListContext value={contextValue}>
104→      <div
105→        ref={containerRef}
106→        className="list"
107→        role="listbox"
108→        aria-activedescendant={`list-item-${activeIndex}`}
109→        tabIndex={0}
110→      >
111→        {children}
112→      </div>
113→    </ListContext>
114→  );
115→}
